#include<bits/stdc++.h>
using namespace std;
long long n,m,k,a[1000005],b[1000005],ans;
int main(){

    cin>>n>>m>>k;

    for(int i=1;i<=n;i++){
        for(int j=i;j<=k;j+=i){
            a[j]++;
        }
    }
    for(int i=1;i<=m;i++){
        for(int j=i;j<=k;j+=i){
            b[j]++;
        }
    }
    for(int i=1;i<=k;i++) ans+=(b[i]*a[i]*i);
    cout<<ans;
}
